/** biome-ignore-all lint/suspicious/noCommentText: TypeScript directive comments needed for form initialization */
import { ActionPageSubmission, AmountAllocation, IActionPage } from '@domain/actionPages';
import { SourceFrequency } from '@domain/entry';
import { PromoCodeShow } from '@domain/promoCode';
import { PublicActionPage } from '@domain/publicActionPage';
import { DonorProfileResponse } from '@state/user/donor_profile';
import { IPaymentMethodForm } from '@ui/components/formControls/compositions/PaymentMethodForm/types';
import { getLocalDonorSession } from '../localDonorSession/getLocalDonorSession';
import { normalizeOccupation } from '../normalizeOccupation';

const EMPTY: unknown[] = [];

export type ActionPageSubmissionForm = Partial<
  ActionPageSubmission &
    IPaymentMethodForm & {
      customFieldResponsesAttributes: { [key: string]: string };
      employed?: boolean;
      frequency?: string;
      makeDonationAs?: 'individual' | 'organization' | 'pac' | 'business';
      organization?: string;
      organizationType?: string;
      otherAmount?: string;
      promoCode?: string;
      promoCodeAttributes?: PromoCodeShow;
      promoCodeDiscount?: number;
    } & {
      actionPageId: string;
      donorProfile?: DonorProfileResponse;
      expressCheckoutMethod?: 'applepay' | 'googlepay' | 'paypal' | 'venmo';
      hasValidDonorPaymentMethod?: boolean;
      hasValidUpgradePaymentMethod?: boolean;
      hideExpressCheckoutControls?: boolean;
      isInUpgradeChain?: boolean;
      pageType: IActionPage['pageType'];
      paymentMethodId?: string;
      savePaymentMethod?: boolean;
    } & {
      futurePledgeDate?: string | null;
      futurePledgeSelected?: boolean;
    } & {
      customFieldPositionsAttributes?: PublicActionPage['fieldConfiguration']['customFieldPositionsAttributes'];
    }
>;

type Props = {
  accountSlug?: string;
  actionPage: PublicActionPage;
  actionPageSlug?: string;
  enableFuturePledgePreCheck?: boolean;
  fundAmountsOverride?: string[];
  fundIdsOverride?: string[];
  isEmbedded: boolean;
  isPreview?: boolean;
  isRestricted?: boolean;
  searchParams: URLSearchParams;
};

export const getActionPageInitialValues = ({
  accountSlug,
  actionPage,
  actionPageSlug,
  enableFuturePledgePreCheck,
  fundAmountsOverride = [],
  fundIdsOverride = EMPTY as string[],
  isEmbedded,
  isPreview = false,
  isRestricted,
  searchParams,
}: Props) => {
  let pageDictionary: Record<string, string> = {};

  const localDonorSession = isPreview ? null : getLocalDonorSession();

  const {
    addressAttributes,
    email,
    employed,
    employerAddressAttributes,
    employerName,
    firstName,
    lastName,
    makeDonationAs,
    middleName,
    occupation,
    organization,
    organizationType,
    phone,
    suffix,
    title,
  } = localDonorSession || {};

  const {
    displayAddress,
    displayEmail,
    displayEmployment,
    displayName,
    displayOrganizationType,
    displayPhone,
    includeEmployerAddress,
    includeEmployerName,
    includeMiddleName,
    includeOccupation,
    includeOrganization,
    includeSuffix,
    includeTitle,
  } = actionPage.fieldConfiguration;

  try {
    pageDictionary = actionPage.pageDictionary ? JSON.parse(actionPage.pageDictionary) : {};
  } catch (_err) {
    pageDictionary = {};
  }

  // find internal names for all custom fields
  const customFieldResponsesAttributes =
    actionPage.fieldConfiguration.customFieldPositionsAttributes?.reduce(
      (acc, cur) => {
        // We bind to customFieldId because all we need for submit is customField and data
        // @ts-ignore
        acc[cur.customFieldAttributes.id] =
          searchParams.get(cur.customFieldAttributes?.internalName ?? '') ??
          pageDictionary[cur.customFieldAttributes?.internalName] ??
          cur.defaultValue ??
          (cur.customFieldAttributes.inputType !== 'requirement' &&
            cur.customFieldAttributes.options.value) ??
          '';
        return acc;
      },
      {} as ActionPageSubmissionForm['customFieldResponsesAttributes']
    );

  let initialAmount =
    (actionPage.amountConfiguration?.amountPresets?.default?.length === 1 &&
    actionPage.pageType === 'donation'
      ? actionPage.amountConfiguration.amountPresets.default[0].amount
      : actionPage.amountConfiguration?.amountPresets?.default?.find((a) => a.default)?.amount) ??
    0;

  const amountAllocationsAttributes: AmountAllocation[] = [];

  if (
    actionPage.fundConfiguration?.multiFundModifiable &&
    fundAmountsOverride.length > 0 &&
    fundIdsOverride.length === fundAmountsOverride.length
  ) {
    fundAmountsOverride.forEach((amount, index) => {
      amountAllocationsAttributes.push({
        actionPagesFundId: fundIdsOverride[index],
        amount: parseFloat(parseFloat(amount).toFixed(2)) * 100,
        fundType:
          actionPage.fundConfiguration?.fundSelectionsAttributes?.find(
            (selection) => selection.fundId === fundIdsOverride[index]
          )?.type ?? '',
      });
    });

    initialAmount = amountAllocationsAttributes.reduce((acc, x) => acc + x.amount, 0);
  }

  const {
    businessDirectDebitEnabled,
    creditCardEnabled,
    paypalEnabled,
    personalDirectDebitEnabled,
  } = actionPage.paymentConfiguration || {};

  const referrerUrlEl = document.querySelector('head > meta[name="referrer-to-form"]');

  const initialValues: ActionPageSubmissionForm = {
    accountSlug: accountSlug || actionPage.account.slug,
    actionPageId: actionPage.id,
    actionPageSlug,
    addressAttributes: {
      city: displayAddress ? addressAttributes?.city || '' : '',
      country: displayAddress
        ? actionPage.fieldConfiguration.addressType === 'zip' || isRestricted
          ? 'US'
          : actionPage.pageType === 'lead'
            ? ''
            : addressAttributes?.country || ''
        : '',
      line1: displayAddress ? addressAttributes?.line1 || '' : '',
      line2: displayAddress ? addressAttributes?.line2 || '' : '',
      postalCode: displayAddress ? addressAttributes?.postalCode || '' : '',
      region: displayAddress ? addressAttributes?.region || '' : '',
    },
    amountAllocationsAttributes,
    communicationsConsentEmail: !actionPage.fieldConfiguration.communicationsConsentOptIn,
    communicationsConsentPhone: false,
    // @ts-ignore
    csrfToken: actionPage.csrfToken,

    customerCoveredFees:
      actionPage.pageType === 'storefront' ||
      actionPage.paymentConfiguration?.feeCoverType === 'opt_out' ||
      actionPage.paymentConfiguration?.feeCoverType === 'required',

    customFieldPositionsAttributes: actionPage?.fieldConfiguration?.customFieldPositionsAttributes,

    customFieldResponsesAttributes,

    email: displayEmail ? email || '' : '',
    employed: displayEmployment
      ? employed !== undefined && employed !== null
        ? employed
        : true
      : null,
    employerAddressAttributes: {
      city:
        displayEmployment && includeEmployerAddress ? employerAddressAttributes?.city || '' : '',
      country:
        displayEmployment && includeEmployerAddress
          ? employerAddressAttributes?.country ||
            (actionPage.fieldConfiguration.addressType === 'zip' || isRestricted ? 'US' : '') ||
            ''
