  | 'messageId'
  | 'upgradeConfigurationId';

type ConfigurationState = {
  bulkUpdateConfigurationId?: string;
  editing?: {
    key: ConfigurationKey;
    shared: boolean;
  };
  error?: IErrorResponse;
  loading: ConfigurationKey[];
};

type ConfigurationMethods = {
  onBulkUpdate: (id: string | undefined) => void;
  onCancel: () => void;
  onConfigurationError: (key: ConfigurationKey, errors: IErrorResponse) => void;
  onEdit: (key: ConfigurationKey, shared: boolean) => void;
  onLoaded: (key: ConfigurationKey) => void;
  onLoading: (key: ConfigurationKey) => void;
  onNavigate: (performNavigation: () => void) => void;
  onPostPublish: () => Promise<unknown>;
  onPrePublish: () => Promise<unknown>;
  setNavigateCallback: (callback?: (performNavigation: () => void) => void) => void;
  setPostPublishCallback: (callback?: () => Promise<unknown>) => void;
  setPrePublishCallback: (callback?: () => Promise<unknown>) => void;
};

type ConfigurationStore = ConfigurationState & ConfigurationMethods;

const initialState: ConfigurationState = {
  bulkUpdateConfigurationId: undefined,
  editing: undefined,
  error: {},
  loading: [] as ConfigurationKey[],
};

export const useConfigurationStore = create<ConfigurationStore>((set) => ({
  ...initialState,
  onBulkUpdate: (id) => set((state) => ({ ...state, bulkUpdateConfigurationId: id })),
  onCancel: () =>
    set((state) => ({
      ...state,
      bulkUpdateConfigurationId: undefined,
      editing: undefined,
      error: {},
    })),
  onConfigurationError: (key, { errors = [] }) =>
    set((state) => ({
      ...state,
      error: {
        errors: (state.error?.errors ?? []).concat(
          errors.map(({ attribute, details }) => ({
            attribute: `${key}.${attribute}`,
            details: details.map((detail) => `${toTitleCase(attribute)} ${detail}`),
          }))
        ),
      },
    })),
